use dioxus::prelude::*;

/// Инлайн lucide-иконки (24x24, stroke). `star` — заливная.
/// Размер по умолчанию 24; в большинстве мест перекрывается CSS (`svg { width: ... }`).
#[component]
pub fn Icon(name: String, #[props(default = 24)] size: i32, #[props(default)] class: String) -> Element {
    let filled = name == "star";
    let inner = icon_inner(&name);
    rsx! {
        svg {
            class: "{class}",
            width: "{size}",
            height: "{size}",
            view_box: "0 0 24 24",
            fill: if filled { "currentColor" } else { "none" },
            stroke: if filled { "none" } else { "currentColor" },
            stroke_width: "2",
            stroke_linecap: "round",
            stroke_linejoin: "round",
            dangerous_inner_html: "{inner}",
        }
    }
}

